=Analyze this lead and provide a qualification score.

Lead Info:
- Name: {{ $json.FirstName }} {{ $json.LastName }}
- Email: {{ $json.Email }} (Validation: {{ $json.EmailValidation }}, Score: {{ $json.BounceScore }})
- Company: {{ $json.Company }}
- Domain: {{ $json.CompanyDomain }}
- Location: {{ $json.Location }}
- Employee Count: {{ $json.EmployeeCount }}
- Industry: {{ $json.Industry }}
- ICP Match: {{ $json.ICP_Match }} (Score: {{ $json.ICP_Score }})

Web Research about this company:
{{ $json._webSearchContext }}

Target ICP: USA-based telecom companies with 50+ employees.
Use the web research to verify or correct the table data. If web data contradicts table data, trust web data.

Respond in JSON: {"ai_score": <1-100>, "qualification": "<Qualified|Needs Review|Not Qualified>", "notes": "<2-3 sentences>"}

parameters.jsCode:
const items = $input.all();
const results = [];
for (const item of items) {
  const prevData = $('Merge Search + Lead').first().json;
  let aiOutput = item.json.output || item.json.text || '';
  let aiScore = 0; let qualification = 'Needs Review'; let notes = '';
  try {
    const jsonMatch = aiOutput.match(/\{[\s\S]*?\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      aiScore = Math.min(100, Math.max(0, parseInt(parsed.ai_score) || 0));
      qualification = ['Qualified', 'Needs Review', 'Not Qualified'].includes(parsed.qualification) ? parsed.qualification : 'Needs Review';
      notes = parsed.notes || '';
    }
  } catch (e) { notes = 'AI parsing error: ' + aiOutput.substring(0, 200); }
  // SECURITY: UNSURE fallback - low confidence when no web data
  const noWebData = (prevData._webSearchContext || '').startsWith('No web data');
  const uncertainLanguage = /unsure|insufficient|cannot determine|not enough/i.test(notes);
  if ((aiScore >= 35 && aiScore <= 65 && noWebData) || uncertainLanguage) {
    qualification = 'Needs Review';
    notes = (notes ? notes + ' | ' : '') + 'Low confidence: limited verification data';
  }
  const status = qualification === 'Qualified' ? 'Qualified' : qualification === 'Not Qualified' ? 'Rejected' : 'Needs Review';
  results.push({ json: { ...prevData, AI_Score: aiScore, Qualification: qualification, AI_Notes: notes, Status: status } });
}
return results;

