// Count records processed + API usage stats for monitoring dashboard
let totalLeads = 0;
let uniqueLeads = 0;
let emailsVerified = 0;
let icpPassed = 0;
let icpSkipped = 0;

try { totalLeads = $('Filter Unprocessed').all().length; } catch(e) {}
try { uniqueLeads = $('Deduplicate Leads').all().length; } catch(e) {}
try { emailsVerified = $('Collect Emails for Batch').first().json.count || 0; } catch(e) {}
try {
  const icpResults = $('ICP Rule Check').all();
  icpPassed = icpResults.filter(i => i.json._icpScoreNum >= 1).length;
  icpSkipped = icpResults.filter(i => i.json._icpScoreNum === 0).length;
} catch(e) {}

const tavilySearches = icpPassed;
const openRouterCalls = icpPassed;
const bouncerCalls = emailsVerified > 0 ? 1 : 0;

const tavilyCost = tavilySearches * 0.01;
const openRouterCost = openRouterCalls * 0.002;
const totalEstCost = tavilyCost + openRouterCost;

const timestamp = new Date().toISOString();
return [{ json: {
  count: totalLeads,
  timestamp,
  totalLeads,
  uniqueLeads,
  duplicatesRemoved: totalLeads - uniqueLeads,
  emailsVerified,
  bouncerCalls,
  icpPassed,
  icpSkipped,
  tavilySearches,
  openRouterCalls,
  llmTokensSaved: icpSkipped + ' leads skipped AI',
  estCostUSD: '$' + totalEstCost.toFixed(4)
} }];
